import{c as r,Q as o,j as e,m as l}from"./chunks/framework.j5cTrcw1.js";const g=JSON.parse('{"title":"使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"usage.md","filePath":"usage.md"}'),i={name:"usage.md"};function t(n,a,s,d,h,u){return o(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="使用指南" tabindex="-1">使用指南 <a class="header-anchor" href="#使用指南" aria-label="Permalink to &quot;使用指南&quot;">​</a></h1><h2 id="_1-仪表盘-dashboard" tabindex="-1">1. 仪表盘 (Dashboard) <a class="header-anchor" href="#_1-仪表盘-dashboard" aria-label="Permalink to &quot;1. 仪表盘 (Dashboard)&quot;">​</a></h2><p>登录系统后首先看到的是仪表盘，这里展示了系统的整体运行状态，包括：</p><ul><li>在线节点数量</li><li>用户总数</li><li>流量统计信息</li></ul><h2 id="_2-节点管理-node" tabindex="-1">2. 节点管理 (Node) <a class="header-anchor" href="#_2-节点管理-node" aria-label="Permalink to &quot;2. 节点管理 (Node)&quot;">​</a></h2><p>节点是实际承载流量转发的服务器。</p><ul><li><strong>添加节点</strong>: 点击“添加”，获取密钥用于节点端安装。</li><li><strong>管理</strong>: 可以查看节点在线状态、版本信息，以及对节点进行编辑或删除。</li></ul><h2 id="_3-用户管理-user" tabindex="-1">3. 用户管理 (User) <a class="header-anchor" href="#_3-用户管理-user" aria-label="Permalink to &quot;3. 用户管理 (User)&quot;">​</a></h2><p>管理员可以创建和管理普通用户。</p><ul><li><strong>创建用户</strong>: 设置用户名、密码、流量配额等。</li><li><strong>用户组</strong>: 可以将用户分配到不同的组 (Group)，便于统一管理权限或策略。</li></ul><h2 id="_4-转发管理-forward" tabindex="-1">4. 转发管理 (Forward) <a class="header-anchor" href="#_4-转发管理-forward" aria-label="Permalink to &quot;4. 转发管理 (Forward)&quot;">​</a></h2><p>这是核心功能区，用于设置端口转发规则。</p><ul><li><strong>端口转发</strong>: 将节点服务器的某个端口流量转发到目标地址。 <ul><li><strong>协议</strong>: 支持 TCP / UDP。</li><li><strong>入口</strong>: 选择入口节点和监听端口。</li><li><strong>出口</strong>: 设置目标 IP 和端口。</li></ul></li><li><strong>隧道转发</strong>: 用于更复杂的网络穿透场景（具体配置视业务需求而定）。</li></ul><h2 id="_5-限制与策略-limit" tabindex="-1">5. 限制与策略 (Limit) <a class="header-anchor" href="#_5-限制与策略-limit" aria-label="Permalink to &quot;5. 限制与策略 (Limit)&quot;">​</a></h2><ul><li><strong>限速</strong>: 可以对指定用户或指定隧道进行带宽限制，防止资源滥用。</li><li><strong>计费模式</strong>: 支持配置流量计算方式（单向或双向），适合运营场景。</li></ul><h2 id="_6-系统配置-config" tabindex="-1">6. 系统配置 (Config) <a class="header-anchor" href="#_6-系统配置-config" aria-label="Permalink to &quot;6. 系统配置 (Config)&quot;">​</a></h2><p>在此页面进行系统的全局设置。</p><h2 id="_7-个人设置-profile" tabindex="-1">7. 个人设置 (Profile) <a class="header-anchor" href="#_7-个人设置-profile" aria-label="Permalink to &quot;7. 个人设置 (Profile)&quot;">​</a></h2><ul><li><strong>修改密码</strong>: 为了安全，建议定期修改管理员密码。</li></ul>',19)])])}const c=r(i,[["render",t]]);export{g as __pageData,c as default};
